import subprocess
import os
import hashlib

def generate_requirements_txt():
    """Generate requirements.txt with hashes for all installed packages."""
    with open('requirements.txt', 'w') as f:
        result = subprocess.run(['pip', 'freeze'], stdout=subprocess.PIPE)
        packages = result.stdout.decode().strip().split('\n')
        
        for package in packages:
            name, version = package.split('==')
            hash_value = get_package_hash(name, version)
            f.write(f"{name}=={version} --hash=sha256:{hash_value}\n")

def get_package_hash(package_name, version):
    """Get the hash of the package version."""
    # Download the package wheel file
    wheel_file = f"{package_name}-{version}-py3-none-any.whl"
    subprocess.run(['pip', 'download', f"{package_name}=={version}"], stdout=subprocess.PIPE)
    
    # Calculate the hash
    hasher = hashlib.sha256()
    with open(wheel_file, 'rb') as f:
        while chunk := f.read(8192):
            hasher.update(chunk)
    
    # Clean up the downloaded wheel file
    os.remove(wheel_file)
    
    return hasher.hexdigest()

def update_requirements_txt():
    """Update requirements.txt with the latest versions and hashes."""
    subprocess.run(['pip', 'install', '--upgrade', '-r', 'requirements.txt'])
    generate_requirements_txt()

def install_dependencies():
    """Install dependencies from requirements.txt."""
    subprocess.run(['pip', 'install', '-r', 'requirements.txt'])

def main():
    """Main function to manage dependencies."""
    action = input("Choose an action (generate/update/install): ").strip().lower()
    if action == 'generate':
        generate_requirements_txt()
    elif action == 'update':
        update_requirements_txt()
    elif action == 'install':
        install_dependencies()
    else:
        print("Invalid action. Please choose 'generate', 'update', or 'install'.")

if __name__ == "__main__":
    main()